function parseGitHubRepository(remoteUrl: string | null) {
	if (!remoteUrl) {
		return null;
	}

	const redactedRemoteUrl = redactGitRemoteUrl(remoteUrl);
	const httpsMatch = remoteUrl.match(
		/^https:\/\/(?:[^@]+@)?github\.com\/([^/]+)\/(.+?)(?:\.git)?$/,
