import { existsSync, readFileSync } from "node:fs";
import { spawnSync } from "node:child_process";
import path from "node:path";

type Check = {
	name: string;
	ok: boolean;
	detail: string;
};

type PlannedChange = {
	kind: string;
	target: string;
	action: string;
	reason: string;
	requiresUserConfirmation: boolean;
	wouldWrite: boolean;
};

type Facts = {
	cli: {
		vercel: {
			available: boolean;
			version: string | null;
		};
		pnpm: {
			available: boolean;
			version: string | null;
		};
	};
	auth: {
		vercel: {
			ok: boolean;
			summary: string;
		};
	};
	repo: {
		packageJsonExists: boolean;
		dbMigrateScriptExists: boolean;
		vercelProjectJson: {
			exists: boolean;
			orgIdPresent: boolean;
			projectIdPresent: boolean;
			teamIdPresent: boolean;
		};
	};
	env: {
		present: Record<string, boolean>;
		sources: Record<string, Array<"process" | ".env.local">>;
		missing: string[];
	};
};

type Report = {
	ok: boolean;
	mode: "dry-run";
	phase: "configure-deploy";
	facts: Facts;
	checks: Check[];
	plannedChanges: PlannedChange[];
	needsUser: string[];
	blocked: string[];
	nextActions: string[];
};

const DEPLOY_ENV_KEYS = [
	"ROOT_PASSWORD",
	"AUTH_SECRET",
	"CRON_SECRET",
	"MEDIATOR_SECRET",
	"TURSO_DATABASE_URL",
	"TURSO_AUTH_TOKEN",
	"GITHUB_TOKEN",
	"VERCEL_TOKEN",
	"VERCEL_TEAM_ID",
	"VERCEL_PROJECT_ID",
	"INITIAL_CHATGPT_AUTH_JSON",
	"VERCEL_PROTECTION_BYPASS_SECRET",
	"VERCEL_OIDC_ISSUER",
	"VERCEL_OIDC_AUDIENCE",
	"VERCEL_TEAM_SLUG",
] as const;

function run(command: string, args: string[], timeout = 12_000) {
	return spawnSync(command, args, {
		encoding: "utf8",
		timeout,
	});
}

function parseMode(argv: string[]) {
	const flags = argv.slice(2);
	if (flags.length === 0) {
		return "dry-run" as const;
	}

	if (flags.length === 1 && flags[0] === "--dry-run") {
		return "dry-run" as const;
	}

	if (flags.length === 2 && flags[0] === "--" && flags[1] === "--dry-run") {
		return "dry-run" as const;
	}

	return null;
}

function emitUnsupportedArgsError() {
	const report: Report = {
		ok: false,
		mode: "dry-run",
		phase: "configure-deploy",
		facts: {
			cli: {
				vercel: {
					available: false,
					version: null,
				},
				pnpm: {
					available: false,
					version: null,
				},
			},
			auth: {
				vercel: {
					ok: false,
					summary: "unsupported arguments",
				},
			},
			repo: {
				packageJsonExists: false,
				dbMigrateScriptExists: false,
				vercelProjectJson: {
					exists: false,
					orgIdPresent: false,
					projectIdPresent: false,
					teamIdPresent: false,
				},
			},
			env: {
				present: {},
				sources: {},
				missing: [],
			},
		},
		checks: [],
		plannedChanges: [],
		needsUser: [],
		blocked: [],
		nextActions: [],
	};

	process.stdout.write(
		`${JSON.stringify(
			{
				...report,
				error:
					"Unsupported arguments. This helper supports no args or --dry-run.",
			},
			null,
			2,
		)}\n`,
	);
	process.exitCode = 1;
}

function checkCommandAvailability(command: string, args: string[] = ["--version"]) {
	const result = run(command, args);
	return {
		available: result.status === 0,
		version:
			result.status === 0
				? ((result.stdout || result.stderr).trim().split("\n")[0] ?? null)
				: null,
		error:
			result.status === 0
				? null
				: (
						result.stderr ||
						result.stdout ||
						result.error?.message ||
						`exit ${result.status}`
					).trim(),
	};
}

function summarizeVercelAuth(result: ReturnType<typeof run>) {
	if (result.error) {
		return result.error.message;
	}

	if (result.status === 0) {
		return "authenticated";
	}

	const output = (result.stderr || result.stdout || "").trim();
	if (!output) {
		return `unauthenticated (exit ${result.status})`;
	}

	return output.split("\n")[0] ?? output;
}

function redactStableId(value: string | null) {
	if (!value) {
		return null;
	}

	if (value.length <= 8) {
		return "<redacted>";
	}

	return `${value.slice(0, 4)}…${value.slice(-4)}`;
}

function parseEnvFile(filePath: string) {
	if (!existsSync(filePath)) {
		return new Set<string>();
	}

	const keys = new Set<string>();
	for (const rawLine of readFileSync(filePath, "utf8").split(/\r?\n/)) {
		const line = rawLine.trim();
		if (!line || line.startsWith("#")) {
			continue;
		}

		const entry = line.startsWith("export ") ? line.slice(7).trim() : line;
		const equalsIndex = entry.indexOf("=");
		if (equalsIndex <= 0) {
			continue;
		}

		const key = entry.slice(0, equalsIndex).trim();
		if (key) {
			keys.add(key);
		}
	}

	return keys;
}

function readVercelProjectJson() {
	const filePath = path.join(process.cwd(), ".vercel/project.json");
	if (!existsSync(filePath)) {
		return {
			exists: false,
			orgIdPresent: false,
			projectIdPresent: false,
			teamIdPresent: false,
		};
	}

	try {
		const parsed = JSON.parse(readFileSync(filePath, "utf8")) as {
			orgId?: string;
			projectId?: string;
			teamId?: string;
		};


